{
  "context": {
    "domain": "soil-testing",
    "action": "catalog/publish",
    "bpp_id": "{{bpp_id}}",
    "bpp_uri": "{{bpp_uri}}",
    "version": "{{version}}",
    "ttl": "PT30S",
    "transaction_id": "{{$randomUUID}}",
    "message_id": "{{$guid}}",
    "timestamp": "{{$isoTimestamp}}"
  },
  "message": {
    "catalog": {
      "providers": [
        {
          "id": "iari-soil-lab-delhi-01",
          "descriptor": {
            "name": "IARI Regional Soil Testing Laboratory"
          },
          "fulfillments": [
            {
              "id": "FULFILLMENT_DROP_01",
              "type": "drop",
              "stops": [
                {
                  "type": "end",
                  "location": {
                    "gps": "28.6378,77.1678",
                    "address": {
                      "street": "Pusa Road, IARI Campus",
                      "city": "New Delhi",
                      "state": "Delhi",
                      "area_code": "110012"
                    }
                  },
                  "instructions": { "name": "Drop off sample at this location" }
                }
              ]
            },
            {
              "id": "FULFILLMENT_PICKUP_02",
              "type": "pickup",
              "stops": [
                {
                  "type": "start",
                  "instructions": { "name": "Schedule Agent Pickup" },
                  "authorization": {
                    "type": "url",
                    "token": "https://iari.gov.in/soil-testing/book-pickup"
                  }
                }
              ]
            }
          ],
          "items": [
            {
              "id": "TEST_MACRO_01",
              "descriptor": {
                "name": "Standard Soil Macronutrient Test",
                "short_desc": "Tests for pH, Nitrogen (N), Phosphorus (P), and Potassium (K)."
              },
              "price": {
                "currency": "INR",
                "value": "500"
              },
              "fulfillment_ids": [
                "FULFILLMENT_DROP_01",
                "FULFILLMENT_PICKUP_02"
              ]
            }
          ]
        }
      ]
    }
  }
}
